def filter(df, params):
    import json
    cats = params.get('categories', [])
    if not cats:
        return df
    mode = params.get('mode', 'include')
    def get_names(ext_val):
        try:
            obj = json.loads(ext_val) if isinstance(ext_val, str) else ext_val
            preds = obj.get('original_predictions', []) if isinstance(obj, dict) else obj
            if isinstance(preds, list):
                return [p.get('name','') for p in preds if isinstance(p, dict)]
            return []
        except:
            return []
    df['_names'] = df['ext'].apply(get_names)
    mask = df['_names'].apply(lambda ns: any(c in ns for c in cats))
    result = df[mask] if mode == 'include' else df[~mask]
    return result.drop(columns=['_names'], errors='ignore')
